let analisisMasaCocida = `
select id,codigoproceso,fechaindustrial,fecharegistro,horaregistro,HORA,KILOS,brixmanual,temperaturamanual,polmanual,phmanual,brixautomatico,polautomatico,pureza from pr_ezi_laboratorio_gral where id= (select max(id) from   pr_ezi_laboratorio_gral where codigoproceso='Masa Cocida de 1era' AND brixmanual IS NOT NULL) union select id,codigoproceso,fechaindustrial,fecharegistro,horaregistro,HORA,KILOS,brixmanual,temperaturamanual,polmanual,phmanual,brixautomatico,polautomatico,pureza from pr_ezi_laboratorio_gral where id= (select max(id) from pr_ezi_laboratorio_gral where codigoproceso='Masa Cocida de 2da' AND brixmanual IS NOT NULL ) union select id,codigoproceso,fechaindustrial,fecharegistro,horaregistro,HORA,KILOS,brixmanual,temperaturamanual,polmanual,phmanual,brixautomatico,polautomatico,pureza from pr_ezi_laboratorio_gral where id= (select max(id) from pr_ezi_laboratorio_gral where codigoproceso='Masa Cocida de 3era' AND brixmanual IS NOT NULL)   ORDER BY codigoproceso;
`;

msg.payload = analisisMasaCocida;

return msg;

let analisisMelaza = `
select id,codigoproceso,fechaindustrial,fecharegistro,horaregistro,HORA,KILOS,brixmanual,temperaturamanual,polmanual,phmanual,brixautomatico,polautomatico,pureza from pr_ezi_laboratorio_gral where id= (select max(id) from   pr_ezi_laboratorio_gral where codigoproceso='Melaza' AND brixmanual IS NOT NULL AND YEAR(fecharegistro)=YEAR(GETDATE()));
`;

msg.payload = analisisMelaza;

return msg;
